  ('cpa-moex-00991', 'cpa', 'cpa-moex-106-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲公司與乙公司合併為丙公司，合併前甲公司之應納稅捐，依稅捐稽徵法規定，應由下列何者負繳納義 務？', '["甲公司", "甲公司之原負責人", "乙公司", "丙公司"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "d6ee7dd2d5b1", "answer_pdf_sha1": "7ebd75063743", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00992', 'cpa', 'cpa-moex-106-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '某乙地價稅繳款通知書載明繳款截止日為11月30日（星期日），應納稅額為新臺幣1萬元，某乙於12月 4日繳納，依稅捐稽徵法規定，應加徵多少滯納金？', '["50元", "100元", "200元", "300元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "d6ee7dd2d5b1", "answer_pdf_sha1": "7ebd75063743", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00993', 'cpa', 'cpa-moex-106-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '稅捐稽徵機關適用法令錯誤、計算錯誤或其他可歸責於政府機關之錯誤，致溢繳稅款者，依稅捐稽徵法 規定，應如何處理？', '["納稅義務人得自繳納之日起2年內提出具體證明申請退還，屆期未申請者不得再行申請", "納稅義務人得自繳納之日起3年內提出具體證明申請退還，屆期未申請者不得再行申請", "稅捐稽徵機關應自知有錯誤原因之日起2年內查明退還，其退還之稅款不以5年內溢繳者為限", "稅捐稽徵機關應自知有錯誤原因之日起2年內查明退還，其退還之稅款以5年內溢繳者為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "d6ee7dd2d5b1", "answer_pdf_sha1": "7ebd75063743", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00994', 'cpa', 'cpa-moex-106-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，下列有關納稅義務之敘述何者正確？', '["共有財產，由管理人負納稅義務；未設管理人者，其為分別共有時，以全體共有人為納稅義務人", "法人、合夥或非法人團體解散清算時，清算人於分配賸餘財產前，應依法按稅捐受清償之順序，繳清 稅捐", "納稅義務人死亡，遺有財產者，應先分割遺產或交付遺贈，再依法按稅捐受清償之順序，繳清稅捐", "營利事業因合併而消滅時，應先繳清其在合併前之應納稅捐，始可合併"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "d6ee7dd2d5b1", "answer_pdf_sha1": "7ebd75063743", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00995', 'cpa', 'cpa-moex-106-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法第5條之1規定，信託契約明訂信託利益之全部或一部之受益人為非委託人者，應課 徵贈與稅，在無特殊情形下，誰為納稅義務人？', '["委託人", "受託人", "受益人", "監察人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "d6ee7dd2d5b1", "answer_pdf_sha1": "7ebd75063743", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00996', 'cpa', 'cpa-moex-106-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，被繼承人死亡前二年內贈與之財產，依規定併入遺產課徵遺產稅者，下列何者 不得自應納遺產稅額內扣抵？', '["已納之契稅", "已納之土地增值稅", "已納之贈與稅", "已納之贈與稅與土地增值稅按郵政儲金一年期定期存款利率計算之利息"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "d6ee7dd2d5b1", "answer_pdf_sha1": "7ebd75063743", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00997', 'cpa', 'cpa-moex-106-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，遺產稅或贈與稅應納稅額在30萬元以上，納稅義務人確有困難，不能一次繳納 現金時，得於納稅期限內，向該管稽徵機關申請，分幾期以內繳納，每期間隔以不超過幾個月為限？', '["12期；1個月", "18期；2個月", "24期；1個月", "24期；2個月"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "d6ee7dd2d5b1", "answer_pdf_sha1": "7ebd75063743", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00998', 'cpa', 'cpa-moex-106-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '設某甲繼承其父親之遺產，遺產稅之應納稅額為100萬元，某甲以價值200萬元之實物申請抵繳應納稅 款，該抵繳實物嗣後於處理變價後，得價款300萬元，請問依遺產及贈與稅法規定應退還某甲多少金額？', '["100萬元", "200萬元", "150萬元", "120萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "d6ee7dd2d5b1", "answer_pdf_sha1": "7ebd75063743", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00999', 'cpa', 'cpa-moex-106-1cd83735', 'sub-cpa-06', NULL, 'essay', '甲公司於X7年4月1日發行面額$10、市價$36之普通股10,000股，以取得乙
公司現金以外之淨資產，合併完成後乙公司即告解散。合併前乙公司資產負債
表如下：
帳面金額  公允價值    帳面金額  公允價值
現金  $120,000  $120,000  應付帳款  $140,000  $130,000
應收帳款  170,000  170,000  應付票據  160,000  190,000
土地  150,000  260,000  普通股股本（面額$10） 300,000
建築物  130,000  120,000  資本公積  140,000
設備  180,000  150,000  保留盈餘  50,000
商譽    40,000
合計  $790,000  $820,000    合計  $790,000
依合併契約之規定，若X7年12月31日甲公司普通股之每股市價低於$36，甲
公司必須額外發行普通股3,500股給予乙公司原有股東。X7年4月1日甲公司
評估或有對價之公允價值為$90,000，X7年10月1日甲公司因獲得於收購日已
存在之事實的新資訊，經重新評估或有對價之公允價值應為$100,000。X7年12月
31 日甲公司普通股之每股市價跌至$31，甲公司依合併契約之規定而另發行普
通股3,500股給予乙公司原有股東。
試作：X7年4月1日甲公司合併乙公司之分錄。（5分）
X7年10月1日甲公司重新評估或有對價公允價值之相關分錄。（2分）
X7年12月31日甲公司額外發行普通股3,500股之分錄。（3分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "b5019080d1a3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0202", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "高等會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01000', 'cpa', 'cpa-moex-106-1cd83735', 'sub-cpa-06', NULL, 'essay', '甲公司於X1年 1月 1日取得乙公司80%的股權，並採權益法處理該項投資，
